        if offset.find(':') > -1:
            offset_hours,offset_min = offset.split(':')
            offset_hours = int(offset_hours)
            offset_min = int(offset_min)
        else:
            offset_hours = int(offset[0:1])
            offset_min = int(offset[2:3])


