        if params is None:
            params = {}
        Resource.verify_keys(params, Address.create_signature())
        if "customer_id" not in params:
            raise KeyError("customer_id must be provided")
        if not re.search(r"\A[0-9A-Za-z_-]+\Z", params["customer_id"]):
